// frontend/src/components/Navbar/Navbar.js
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

// PERBAIKAN: Menambahkan 'userRole' ke dalam destructuring props
const Navbar = ({ activeMenu, setActiveMenu, isAuthenticated, userRole, handleLogout }) => {
    const navigate = useNavigate();
    const [isOpen, setIsOpen] = useState(false);

    // State untuk melacak elemen mana yang sedang di-hover
    const [hoveredMenu, setHoveredMenu] = useState(null);

    const navigateTo = (path, menuId) => {
        if (setActiveMenu) setActiveMenu(menuId);
        navigate(path);
        setIsOpen(false);
    };

    // Style dasar untuk menu
    const getMenuStyle = (menuId) => ({
        background: 'none',
        border: 'none',
        color: hoveredMenu === menuId ? '#ea580c' : '#fff', 
        fontWeight: '700',
        cursor: 'pointer',
        fontSize: '14px',
        transition: 'color 0.3s ease'
    });

    return (
        <nav style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'center', 
            padding: '20px 5%', 
            background: '#0c0a09', 
            borderBottom: '1px solid #262626',
            position: 'relative'
        }}>
            {/* Logo */}
            <div onClick={() => navigateTo('/', 'home')} style={{ cursor: 'pointer' }}>
                <h3 style={{ color: '#fef3c7', margin: 0 }}>PasukanYerusSolo</h3>
            </div>

            {/* Menu Navigasi */}
            <div style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
                {/* Contoh penggunaan userRole yang sudah didefinisikan */}
                {isAuthenticated && userRole === 'hrd' && (
                    <button style={getMenuStyle('hrd')} onClick={() => navigateTo('/hrd/dashboard', 'hrd')}>
                        Dashboard HRD
                    </button>
                )}

                {isAuthenticated ? (
                    <button onClick={handleLogout} style={getMenuStyle('logout')}>
                        Keluar
                    </button>
                ) : (
                    <button onClick={() => navigate('/login')} style={getMenuStyle('login')}>
                        Login
                    </button>
                )}
            </div>

            <style>{`
                @media (max-width: 768px) {
                    .nav-menu { display: none !important; }
                }
            `}</style>
        </nav>
    );
};

export default Navbar;
